import React from "react";
import { useState, useEffect, useCallback, useRef } from "react";
import { Search, Disc3, User, Plus, X, RefreshCw, ListMusic, Users, Upload, FileSpreadsheet, CheckCircle2, AlertCircle } from "lucide-react";
import * as XLSX from "xlsx";

const FONT_LINK = "https://fonts.googleapis.com/css2?family=Playfair+Display:ital,wght@1,500;1,700&family=Barlow:wght@400;500;600;700&family=Space+Mono:wght@400;700&display=swap";

const STORAGE_KEY = "volver-wantlist-entries";

// Discogs personal access token — unlocks thumb/cover_image data on search results.
// Note: this is visible to anyone who views the page source, since this is a
// client-side app with no backend. Discogs personal tokens don't grant
// account-modifying access for search calls, so this is fine for a tool like this.
const DISCOGS_TOKEN = "dYpwRhhtUGpiisteXZdsylSdXTVVAWNvMtdPEWFV";

// Volver Records logo — black field, white skyline linework, red beacon + wordmark gradient
const LOGO_SRC = "data:image/png;base64,";

// Palette pulled from the logo
const COL = {
  bg: "#000000",
  panel: "#121212",
  panelBorder: "#2A2A2A",
  line: "#F2F2F2", // skyline white
  red: "#E11B23", // beacon / gradient red
  redDeep: "#7A0E12",
  text: "#F5F0EC",
  muted: "#9A9A9A",
};

function useFonts() {
  useEffect(() => {
    if (!document.getElementById("wantlist-fonts")) {
      const link = document.createElement("link");
      link.id = "wantlist-fonts";
      link.rel = "stylesheet";
      link.href = FONT_LINK;
      document.head.appendChild(link);
    }
  }, []);
}

function RecordThumb({ src, alt, size = 56 }) {
  return (
    <div
      style={{
        width: size,
        height: size,
        borderRadius: "50%",
        overflow: "hidden",
        flexShrink: 0,
        border: "2px solid #E11B23",
        background: "#000000",
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        position: "relative",
        transition: "transform 0.6s cubic-bezier(0.2, 0.8, 0.2, 1)",
      }}
      className="record-thumb"
    >
      {src ? (
        <img src={src} alt={alt} style={{ width: "100%", height: "100%", objectFit: "cover" }} />
      ) : (
        <Disc3 size={size * 0.5} color="#E11B23" strokeWidth={1.5} />
      )}
      <div
        style={{
          position: "absolute",
          width: size * 0.18,
          height: size * 0.18,
          borderRadius: "50%",
          background: "#000000",
          border: "1px solid #3A3A3A",
        }}
      />
    </div>
  );
}

export default function DiscogsWantList() {
  useFonts();

  const [name, setName] = useState("");
  const [query, setQuery] = useState("");
  const [results, setResults] = useState([]);
  const [searching, setSearching] = useState(false);
  const [searchError, setSearchError] = useState(null);
  const [manualMode, setManualMode] = useState(false);
  const [manual, setManual] = useState({ title: "", artist: "", year: "", url: "" });

  const [entries, setEntries] = useState([]);
  const [loadingEntries, setLoadingEntries] = useState(true);
  const [view, setView] = useState("add"); // add | byItem | byPerson
  const [toast, setToast] = useState(null);

  // Spreadsheet upload
  const fileInputRef = useRef(null);
  const [uploadRows, setUploadRows] = useState(null); // parsed + previewed rows, awaiting confirm
  const [uploadError, setUploadError] = useState(null);
  const [uploadName, setUploadName] = useState("");
  const [uploading, setUploading] = useState(false);

  const showToast = (msg) => {
    setToast(msg);
    setTimeout(() => setToast(null), 2200);
  };

  const loadEntries = useCallback(async () => {
    setLoadingEntries(true);
    try {
      const res = await window.storage.get(STORAGE_KEY, true);
      setEntries(res && res.value ? JSON.parse(res.value) : []);
    } catch (e) {
      setEntries([]);
    } finally {
      setLoadingEntries(false);
    }
  }, []);

  useEffect(() => {
    loadEntries();
  }, [loadEntries]);

  const saveEntries = async (next) => {
    setEntries(next);
    try {
      await window.storage.set(STORAGE_KEY, JSON.stringify(next), true);
    } catch (e) {
      showToast("Couldn't save — try again");
    }
  };

  const runSearch = async () => {
    if (!query.trim()) return;
    setSearching(true);
    setSearchError(null);
    setResults([]);
    try {
      const url = `https://api.discogs.com/database/search?q=${encodeURIComponent(query)}&type=release&per_page=8&token=${DISCOGS_TOKEN}`;
      const res = await fetch(url);
      if (!res.ok) throw new Error("bad response");
      const data = await res.json();
      if (!data.results || data.results.length === 0) {
        setSearchError("No results found on Discogs. Try a different search, or add it by hand below.");
        setManualMode(true);
      } else {
        // Discogs' search endpoint never includes thumb/cover_image, even
        // authenticated — image data only lives on each item's own
        // release/master resource. Show titles immediately, then fetch each
        // one's real thumbnail in the background and fill it in as it arrives.
        setResults(data.results);
        data.results.forEach((item, idx) => {
          if (!item.resource_url) return;
          fetch(`${item.resource_url}?token=${DISCOGS_TOKEN}`)
            .then((r) => (r.ok ? r.json() : null))
            .then((detail) => {
              if (!detail) return;
              const thumb = detail.thumb || (detail.images && detail.images[0] && detail.images[0].uri150) || null;
              if (!thumb) return;
              setResults((prev) => {
                const next = [...prev];
                if (next[idx] && next[idx].id === item.id) {
                  next[idx] = { ...next[idx], thumb };
                }
                return next;
              });
            })
            .catch(() => {});
        });
      }
    } catch (err) {
      setSearchError(
        "Discogs search couldn't load from here (this can happen depending on where the widget is hosted). Add the item by hand instead — just paste the details from Discogs."
      );
      setManualMode(true);
    } finally {
      setSearching(false);
    }
  };

  const addEntry = async (item) => {
    if (!name.trim()) {
      showToast("Add your name first");
      return;
    }
    const entry = {
      id: `${Date.now()}-${Math.random().toString(36).slice(2, 8)}`,
      name: name.trim(),
      title: item.title,
      thumb: item.thumb || item.cover_image || null,
      url: item.uri ? `https://www.discogs.com${item.uri}` : null,
      addedAt: new Date().toISOString(),
    };
    const next = [entry, ...entries];
    await saveEntries(next);
    showToast(`Added "${item.title}" to your want list`);
  };

  const addManual = async () => {
    if (!name.trim()) {
      showToast("Add your name first");
      return;
    }
    if (!manual.title.trim()) {
      showToast("Add a title");
      return;
    }
    const label = [manual.title.trim(), manual.artist.trim(), manual.year.trim()]
      .filter(Boolean)
      .join(" — ");
    const entry = {
      id: `${Date.now()}-${Math.random().toString(36).slice(2, 8)}`,
      name: name.trim(),
      title: manual.artist.trim() ? `${manual.artist.trim()} – ${manual.title.trim()}` : manual.title.trim(),
      thumb: null,
      year: manual.year.trim(),
      url: manual.url.trim() || null,
      addedAt: new Date().toISOString(),
    };
    void label;
    const next = [entry, ...entries];
    await saveEntries(next);
    setManual({ title: "", artist: "", year: "", url: "" });
    showToast(`Added "${entry.title}" to your want list`);
  };

  // --- Spreadsheet upload ---
  // Accepts CSV or XLSX. Looks for columns (case-insensitive, flexible naming):
  // name/person, title/album, artist, year, url/link
  const COLUMN_ALIASES = {
    name: ["name", "person", "your name", "requested by"],
    title: ["title", "album", "item", "record"],
    artist: ["artist", "band"],
    year: ["year", "release year"],
    url: ["url", "link", "discogs url", "discogs link"],
  };

  const findColumn = (headerRow, aliases, claimed) => {
    const lower = headerRow.map((h) => (h || "").toString().trim().toLowerCase());
    // First pass: exact match against known aliases
    for (const alias of aliases) {
      const idx = lower.indexOf(alias);
      if (idx !== -1 && !claimed.has(idx)) return idx;
    }
    // Second pass: forgiving — header just needs to contain the alias word
    // (e.g. "Recording Artist", "Item URL" still match). Columns already
    // claimed by a more specific field (checked first, see call order below)
    // are skipped so e.g. "Artist Name" doesn't get stolen by the name field.
    for (const alias of aliases) {
      const idx = lower.findIndex((h, i) => h.includes(alias) && !claimed.has(i));
      if (idx !== -1) return idx;
    }
    return -1;
  };

  const handleFileSelect = (e) => {
    const file = e.target.files && e.target.files[0];
    if (!file) return;
    setUploadError(null);
    setUploadRows(null);

    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const data = evt.target.result;
        const workbook = XLSX.read(data, { type: "binary" });
        const sheet = workbook.Sheets[workbook.SheetNames[0]];
        const rows = XLSX.utils.sheet_to_json(sheet, { header: 1, defval: "" });

        if (!rows || rows.length < 2) {
          setUploadError("That file looks empty — needs a header row plus at least one item.");
          return;
        }

        const header = rows[0];
        // Claim columns in order from most-specific to least-specific field,
        // so e.g. a column literally called "Artist Name" is matched as
        // Artist (not stolen by the generic "name" field) since artist is
        // resolved first and marks its column as claimed.
        const claimed = new Set();
        const titleCol = findColumn(header, COLUMN_ALIASES.title, claimed);
        if (titleCol !== -1) claimed.add(titleCol);
        const artistCol = findColumn(header, COLUMN_ALIASES.artist, claimed);
        if (artistCol !== -1) claimed.add(artistCol);
        const urlCol = findColumn(header, COLUMN_ALIASES.url, claimed);
        if (urlCol !== -1) claimed.add(urlCol);
        const yearCol = findColumn(header, COLUMN_ALIASES.year, claimed);
        if (yearCol !== -1) claimed.add(yearCol);
        const nameCol = findColumn(header, COLUMN_ALIASES.name, claimed);

        if (titleCol === -1) {
          setUploadError(
            "Couldn't find a title/album column. Rename a column to \"Title\" or \"Album\" and try again."
          );
          return;
        }

        const parsed = rows.slice(1)
          .filter((r) => r[titleCol] && r[titleCol].toString().trim())
          .map((r) => ({
            name: nameCol !== -1 ? (r[nameCol] || "").toString().trim() : "",
            title: (r[titleCol] || "").toString().trim(),
            artist: artistCol !== -1 ? (r[artistCol] || "").toString().trim() : "",
            year: yearCol !== -1 ? (r[yearCol] || "").toString().trim() : "",
            url: urlCol !== -1 ? (r[urlCol] || "").toString().trim() : "",
          }));

        if (parsed.length === 0) {
          setUploadError("No rows with a title were found in that file.");
          return;
        }

        setUploadRows(parsed);
        // If the sheet doesn't have its own name column, fall back to the name typed above
        if (nameCol === -1) setUploadName(name.trim());
      } catch (err) {
        setUploadError("Couldn't read that file. Make sure it's a .csv or .xlsx file.");
      }
    };
    reader.onerror = () => setUploadError("Couldn't read that file.");
    reader.readAsBinaryString(file);
  };

  const confirmUpload = async () => {
    if (!uploadRows) return;
    const fallbackName = uploadName.trim();
    const rowsNeedName = uploadRows.filter((r) => !r.name && !fallbackName);
    if (rowsNeedName.length > 0) {
      showToast("Add a name to use for rows missing one");
      return;
    }
    setUploading(true);
    const newEntries = uploadRows.map((r) => {
      const title = r.artist ? `${r.artist} – ${r.title}` : r.title;
      return {
        id: `${Date.now()}-${Math.random().toString(36).slice(2, 8)}`,
        name: r.name || fallbackName,
        title,
        thumb: null,
        year: r.year || "",
        url: r.url || null,
        addedAt: new Date().toISOString(),
      };
    });
    const next = [...newEntries, ...entries];
    await saveEntries(next);
    setUploading(false);
    setUploadRows(null);
    setUploadName("");
    if (fileInputRef.current) fileInputRef.current.value = "";
    showToast(`Added ${newEntries.length} item${newEntries.length !== 1 ? "s" : ""} from spreadsheet`);
  };

  const cancelUpload = () => {
    setUploadRows(null);
    setUploadError(null);
    setUploadName("");
    if (fileInputRef.current) fileInputRef.current.value = "";
  };

  const removeEntry = async (id) => {
    const next = entries.filter((e) => e.id !== id);
    await saveEntries(next);
  };

  const toggleFound = async (id) => {
    const next = entries.map((e) => (e.id === id ? { ...e, found: !e.found } : e));
    await saveEntries(next);
  };

  // Group by item title
  const byItem = {};
  entries.forEach((e) => {
    if (!byItem[e.title]) byItem[e.title] = { title: e.title, thumb: e.thumb, url: e.url || null, people: [] };
    if (!byItem[e.title].url && e.url) byItem[e.title].url = e.url;
    byItem[e.title].people.push(e);
  });
  const itemGroups = Object.values(byItem).sort((a, b) => b.people.length - a.people.length);

  // Group by person
  const byPerson = {};
  entries.forEach((e) => {
    if (!byPerson[e.name]) byPerson[e.name] = { name: e.name, items: [] };
    byPerson[e.name].items.push(e);
  });
  const personGroups = Object.values(byPerson).sort((a, b) => b.items.length - a.items.length);

  const tabs = [
    { key: "add", label: "Add items", icon: Plus },
    { key: "byItem", label: "By item", icon: ListMusic },
    { key: "byPerson", label: "By person", icon: Users },
  ];

  return (
    <div
      style={{
        fontFamily: "'Barlow', sans-serif",
        background: "#000000",
        minHeight: "100vh",
        color: "#F5F0EC",
        padding: "0",
      }}
    >
      <style>{`
        .record-thumb:hover { transform: rotate(25deg); }
        .spin { animation: spin 1s linear infinite; }
        @keyframes spin { from { transform: rotate(0deg); } to { transform: rotate(360deg); } }
        ::placeholder { color: #9A9A9A; opacity: 1; }
        input, textarea { font-family: 'Barlow', sans-serif; }
        .mono { font-family: 'Space Mono', monospace; }
        .tab-btn { transition: all 0.15s ease; }
        .entry-row { animation: fadein 0.3s ease; }
        @keyframes fadein { from { opacity: 0; transform: translateY(4px);} to {opacity:1; transform:translateY(0);} }
        .toast { animation: risein 0.25s ease; }
        @keyframes risein { from { opacity:0; transform: translate(-50%, 8px);} to {opacity:1; transform: translate(-50%,0);} }
      `}</style>

      <div style={{ maxWidth: 640, margin: "0 auto", padding: "36px 20px 60px" }}>
        {/* Header */}
        <div style={{ display: "flex", justifyContent: "center", marginBottom: 4 }}>
          <img
            src={LOGO_SRC}
            alt="Volver Records"
            style={{ width: "100%", maxWidth: 340, height: "auto", display: "block" }}
          />
        </div>
        <p
          className="mono"
          style={{
            textAlign: "center",
            color: "#9A9A9A",
            fontSize: 10.5,
            letterSpacing: 2,
            marginTop: -6,
            marginBottom: 22,
          }}
        >
          AUGUST 2026 — JAPAN TRIP WANT LIST
        </p>
        <p style={{ color: "#9A9A9A", fontSize: 14.5, lineHeight: 1.5, marginTop: 14, marginBottom: 28, textAlign: "center" }}>
          Search Discogs, drop what you're hunting for onto the list, and we'll keep an eye out
          for it in the crates. Every entry is tied to a name — nothing gets lost in the shop.
        </p>

        {/* Tabs */}
        <div
          style={{
            display: "flex",
            gap: 4,
            background: "#121212",
            borderRadius: 10,
            padding: 4,
            marginBottom: 24,
            border: "1px solid #2A2A2A",
          }}
        >
          {tabs.map((t) => {
            const Icon = t.icon;
            const active = view === t.key;
            return (
              <button
                key={t.key}
                className="tab-btn"
                onClick={() => setView(t.key)}
                style={{
                  flex: 1,
                  display: "flex",
                  alignItems: "center",
                  justifyContent: "center",
                  gap: 6,
                  padding: "9px 10px",
                  borderRadius: 7,
                  border: "none",
                  cursor: "pointer",
                  background: active ? "#E11B23" : "transparent",
                  color: active ? "#F5F0EC" : "#9A9A9A",
                  fontSize: 13.5,
                  fontWeight: 600,
                }}
              >
                <Icon size={15} />
                {t.label}
              </button>
            );
          })}
        </div>

        {/* ADD VIEW */}
        {view === "add" && (
          <div>
            <label style={{ display: "block", fontSize: 12.5, color: "#9A9A9A", marginBottom: 6, fontWeight: 600, letterSpacing: 1 }}>
              YOUR NAME <span style={{ color: "#E11B23" }}>*</span>
            </label>
            <div style={{ position: "relative", marginBottom: 6 }}>
              <User size={16} color="#9A9A9A" style={{ position: "absolute", left: 12, top: 12 }} />
              <input
                value={name}
                onChange={(e) => setName(e.target.value)}
                placeholder="e.g. Jamie R."
                style={{
                  width: "100%",
                  padding: "10px 12px 10px 36px",
                  borderRadius: 8,
                  border: name.trim() ? "1px solid #2A2A2A" : "1px solid #7A0E12",
                  background: "#121212",
                  color: "#F5F0EC",
                  fontSize: 14.5,
                  boxSizing: "border-box",
                  outline: "none",
                }}
              />
            </div>
            <p className="mono" style={{ fontSize: 10.5, color: "#9A9A9A", margin: "0 0 20px 2px" }}>
              Required — every item gets tied to your name
            </p>

            <label style={{ display: "block", fontSize: 12.5, color: "#9A9A9A", marginBottom: 6, fontWeight: 600, letterSpacing: 1 }}>
              SEARCH DISCOGS
            </label>
            <div style={{ display: "flex", gap: 8, marginBottom: 14 }}>
              <div style={{ position: "relative", flex: 1 }}>
                <Search size={16} color="#9A9A9A" style={{ position: "absolute", left: 12, top: 12 }} />
                <input
                  value={query}
                  onChange={(e) => setQuery(e.target.value)}
                  onKeyDown={(e) => {
                    if (e.key === "Enter") runSearch();
                  }}
                  placeholder="Artist, album, or catalog number"
                  style={{
                    width: "100%",
                    padding: "10px 12px 10px 36px",
                    borderRadius: 8,
                    border: "1px solid #2A2A2A",
                    background: "#121212",
                    color: "#F5F0EC",
                    fontSize: 14.5,
                    boxSizing: "border-box",
                    outline: "none",
                  }}
                />
              </div>
              <button
                type="button"
                onClick={() => runSearch()}
                disabled={searching}
                style={{
                  padding: "0 18px",
                  borderRadius: 8,
                  border: "none",
                  background: "#E11B23",
                  color: "#F5F0EC",
                  fontWeight: 600,
                  fontSize: 14,
                  cursor: "pointer",
                  display: "flex",
                  alignItems: "center",
                  gap: 6,
                }}
              >
                {searching ? <RefreshCw size={15} className="spin" /> : "Search"}
              </button>
            </div>

            {searchError && (
              <div
                style={{
                  background: "#1A0E0F",
                  border: "1px solid #E11B23",
                  borderRadius: 8,
                  padding: "10px 12px",
                  fontSize: 13,
                  color: "#E8B7B7",
                  marginBottom: 16,
                  lineHeight: 1.5,
                }}
              >
                {searchError}
              </div>
            )}

            {/* Live results */}
            {results.length > 0 && (
              <div style={{ marginBottom: 20 }}>
                {results.map((item) => (
                  <div
                    key={item.id}
                    className="entry-row"
                    style={{
                      display: "flex",
                      alignItems: "center",
                      gap: 12,
                      padding: "10px 4px",
                      borderBottom: "1px solid #2A2A2A",
                    }}
                  >
                    <a
                      href={item.uri ? `https://www.discogs.com${item.uri}` : undefined}
                      target="_blank"
                      rel="noopener noreferrer"
                      style={{ flexShrink: 0, cursor: item.uri ? "pointer" : "default" }}
                      title={item.uri ? "View on Discogs" : undefined}
                    >
                      <RecordThumb src={item.thumb || item.cover_image} alt={item.title} size={48} />
                    </a>
                    <div style={{ flex: 1, minWidth: 0 }}>
                      {item.uri ? (
                        <a
                          href={`https://www.discogs.com${item.uri}`}
                          target="_blank"
                          rel="noopener noreferrer"
                          style={{
                            fontSize: 14,
                            fontWeight: 500,
                            color: "#F5F0EC",
                            overflow: "hidden",
                            textOverflow: "ellipsis",
                            whiteSpace: "nowrap",
                            display: "block",
                            textDecoration: "none",
                            borderBottom: "1px solid transparent",
                          }}
                          onMouseEnter={(e) => (e.currentTarget.style.borderBottomColor = "#E11B23")}
                          onMouseLeave={(e) => (e.currentTarget.style.borderBottomColor = "transparent")}
                        >
                          {item.title}
                        </a>
                      ) : (
                        <div style={{ fontSize: 14, fontWeight: 500, color: "#F5F0EC", overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>
                          {item.title}
                        </div>
                      )}
                      <div className="mono" style={{ fontSize: 11, color: "#9A9A9A" }}>
                        {item.year || ""} {item.format ? `· ${item.format.join(", ")}` : ""}
                      </div>
                    </div>
                    <button
                      onClick={() => addEntry(item)}
                      disabled={!name.trim()}
                      title={!name.trim() ? "Add your name first" : undefined}
                      style={{
                        padding: "7px 12px",
                        borderRadius: 7,
                        border: `1px solid ${name.trim() ? "#E11B23" : "#3A3A3A"}`,
                        background: "transparent",
                        color: name.trim() ? "#F5F0EC" : "#6B6B6B",
                        fontSize: 12.5,
                        fontWeight: 600,
                        cursor: name.trim() ? "pointer" : "not-allowed",
                        flexShrink: 0,
                      }}
                    >
                      + Want
                    </button>
                  </div>
                ))}
              </div>
            )}

            {/* Manual add toggle */}
            <div style={{ marginTop: 8 }}>
              <button
                onClick={() => setManualMode((m) => !m)}
                style={{
                  background: "none",
                  border: "none",
                  color: "#E11B23",
                  fontSize: 12.5,
                  fontWeight: 600,
                  cursor: "pointer",
                  padding: 0,
                  marginBottom: 10,
                }}
              >
                {manualMode ? "− Hide manual entry" : "+ Add an item by hand instead"}
              </button>

              {manualMode && (
                <div
                  style={{
                    background: "#121212",
                    border: "1px solid #2A2A2A",
                    borderRadius: 10,
                    padding: 14,
                    display: "flex",
                    flexDirection: "column",
                    gap: 8,
                  }}
                >
                  <input
                    value={manual.title}
                    onChange={(e) => setManual({ ...manual, title: e.target.value })}
                    onKeyDown={(e) => {
                      if (e.key === "Enter") addManual();
                    }}
                    placeholder="Album title *"
                    style={{
                      padding: "9px 10px",
                      borderRadius: 7,
                      border: "1px solid #2A2A2A",
                      background: "#000000",
                      color: "#F5F0EC",
                      fontSize: 14,
                      outline: "none",
                    }}
                  />
                  <div style={{ display: "flex", gap: 8 }}>
                    <input
                      value={manual.artist}
                      onChange={(e) => setManual({ ...manual, artist: e.target.value })}
                      onKeyDown={(e) => {
                        if (e.key === "Enter") addManual();
                      }}
                      placeholder="Artist"
                      style={{
                        flex: 2,
                        padding: "9px 10px",
                        borderRadius: 7,
                        border: "1px solid #2A2A2A",
                        background: "#000000",
                        color: "#F5F0EC",
                        fontSize: 14,
                        outline: "none",
                      }}
                    />
                    <input
                      value={manual.year}
                      onChange={(e) => setManual({ ...manual, year: e.target.value })}
                      onKeyDown={(e) => {
                        if (e.key === "Enter") addManual();
                      }}
                      placeholder="Year"
                      style={{
                        flex: 1,
                        padding: "9px 10px",
                        borderRadius: 7,
                        border: "1px solid #2A2A2A",
                        background: "#000000",
                        color: "#F5F0EC",
                        fontSize: 14,
                        outline: "none",
                      }}
                    />
                  </div>
                  <input
                    value={manual.url}
                    onChange={(e) => setManual({ ...manual, url: e.target.value })}
                    onKeyDown={(e) => {
                      if (e.key === "Enter") addManual();
                    }}
                    placeholder="Link to the item (Discogs, Reverb, etc. — optional)"
                    style={{
                      padding: "9px 10px",
                      borderRadius: 7,
                      border: "1px solid #2A2A2A",
                      background: "#000000",
                      color: "#F5F0EC",
                      fontSize: 14,
                      outline: "none",
                    }}
                  />
                  <button
                    type="button"
                    onClick={() => addManual()}
                    disabled={!name.trim()}
                    title={!name.trim() ? "Add your name first" : undefined}
                    style={{
                      alignSelf: "flex-start",
                      padding: "8px 16px",
                      borderRadius: 7,
                      border: "none",
                      background: name.trim() ? "#E11B23" : "#3A3A3A",
                      color: name.trim() ? "#F5F0EC" : "#6B6B6B",
                      fontWeight: 600,
                      fontSize: 13,
                      cursor: name.trim() ? "pointer" : "not-allowed",
                      marginTop: 4,
                    }}
                  >
                    Add to want list
                  </button>
                </div>
              )}
            </div>

            {/* Spreadsheet upload */}
            <div style={{ marginTop: 28, paddingTop: 20, borderTop: "1px solid #2A2A2A" }}>
              <label style={{ display: "block", fontSize: 12.5, color: "#9A9A9A", marginBottom: 8, fontWeight: 600, letterSpacing: 1 }}>
                OR UPLOAD A SPREADSHEET
              </label>

              {!uploadRows && (
                <div>
                  <input
                    ref={fileInputRef}
                    type="file"
                    accept=".csv,.xlsx,.xls"
                    onChange={handleFileSelect}
                    style={{ display: "none" }}
                    id="wantlist-file-upload"
                  />
                  <button
                    type="button"
                    onClick={() => fileInputRef.current && fileInputRef.current.click()}
                    style={{
                      display: "flex",
                      alignItems: "center",
                      gap: 8,
                      width: "100%",
                      padding: "12px 14px",
                      borderRadius: 8,
                      border: "1px dashed #3A3A3A",
                      background: "#121212",
                      color: "#D8D3CC",
                      fontSize: 13.5,
                      cursor: "pointer",
                      boxSizing: "border-box",
                    }}
                  >
                    <Upload size={16} color="#9A9A9A" />
                    Choose a .csv or .xlsx file
                  </button>
                  <p className="mono" style={{ fontSize: 10.5, color: "#9A9A9A", margin: "8px 2px 0" }}>
                    Columns recognized: Name, Title/Album, Artist, Year, URL — any order, any capitalization
                  </p>
                </div>
              )}

              {uploadError && (
                <div
                  style={{
                    display: "flex",
                    gap: 8,
                    background: "#1A0E0F",
                    border: "1px solid #7A0E12",
                    borderRadius: 8,
                    padding: "10px 12px",
                    fontSize: 13,
                    color: "#E8B7B7",
                    marginTop: 10,
                    lineHeight: 1.5,
                  }}
                >
                  <AlertCircle size={16} style={{ flexShrink: 0, marginTop: 1 }} />
                  <span>{uploadError}</span>
                </div>
              )}

              {uploadRows && (
                <div
                  style={{
                    background: "#121212",
                    border: "1px solid #2A2A2A",
                    borderRadius: 10,
                    padding: 14,
                    marginTop: 10,
                  }}
                >
                  <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 10 }}>
                    <FileSpreadsheet size={16} color="#E11B23" />
                    <span style={{ fontSize: 13.5, fontWeight: 600, color: "#F5F0EC" }}>
                      {uploadRows.length} item{uploadRows.length !== 1 ? "s" : ""} found — review before adding
                    </span>
                  </div>

                  {uploadRows.some((r) => !r.name) && (
                    <div style={{ marginBottom: 12 }}>
                      <label style={{ display: "block", fontSize: 11.5, color: "#9A9A9A", marginBottom: 5 }}>
                        Some rows don't have a name — use this name for those:
                      </label>
                      <input
                        value={uploadName}
                        onChange={(e) => setUploadName(e.target.value)}
                        placeholder="e.g. Jamie R."
                        style={{
                          width: "100%",
                          padding: "8px 10px",
                          borderRadius: 7,
                          border: "1px solid #2A2A2A",
                          background: "#000000",
                          color: "#F5F0EC",
                          fontSize: 13.5,
                          boxSizing: "border-box",
                          outline: "none",
                        }}
                      />
                    </div>
                  )}

                  <div style={{ maxHeight: 220, overflowY: "auto", marginBottom: 12 }}>
                    {uploadRows.map((r, i) => (
                      <div
                        key={i}
                        style={{
                          display: "flex",
                          justifyContent: "space-between",
                          gap: 10,
                          padding: "6px 0",
                          borderBottom: i < uploadRows.length - 1 ? "1px solid #1E1E1E" : "none",
                          fontSize: 12.5,
                        }}
                      >
                        <span style={{ color: "#D8D3CC", flex: 1 }}>
                          {r.artist ? `${r.artist} – ${r.title}` : r.title}
                          {r.year ? ` (${r.year})` : ""}
                        </span>
                        <span className="mono" style={{ color: r.name ? "#9A9A9A" : "#E11B23", flexShrink: 0 }}>
                          {r.name || "uses name above"}
                        </span>
                      </div>
                    ))}
                  </div>

                  <div style={{ display: "flex", gap: 8 }}>
                    <button
                      type="button"
                      onClick={confirmUpload}
                      disabled={uploading}
                      style={{
                        display: "flex",
                        alignItems: "center",
                        gap: 6,
                        padding: "8px 16px",
                        borderRadius: 7,
                        border: "none",
                        background: "#E11B23",
                        color: "#F5F0EC",
                        fontWeight: 600,
                        fontSize: 13,
                        cursor: "pointer",
                      }}
                    >
                      {uploading ? <RefreshCw size={14} className="spin" /> : <CheckCircle2 size={14} />}
                      Add all to want list
                    </button>
                    <button
                      type="button"
                      onClick={cancelUpload}
                      style={{
                        padding: "8px 16px",
                        borderRadius: 7,
                        border: "1px solid #2A2A2A",
                        background: "transparent",
                        color: "#9A9A9A",
                        fontWeight: 600,
                        fontSize: 13,
                        cursor: "pointer",
                      }}
                    >
                      Cancel
                    </button>
                  </div>
                </div>
              )}
            </div>
          </div>
        )}

        {/* BY ITEM VIEW */}
        {view === "byItem" && (
          <div>
            {loadingEntries ? (
              <EmptyState text="Loading the crate…" />
            ) : itemGroups.length === 0 ? (
              <EmptyState text="No items yet. Be the first to add something you're hunting for." />
            ) : (
              itemGroups.map((g) => (
                <div
                  key={g.title}
                  className="entry-row"
                  style={{
                    display: "flex",
                    gap: 12,
                    padding: "14px 4px",
                    borderBottom: "1px solid #2A2A2A",
                  }}
                >
                  <RecordThumb src={g.thumb} alt={g.title} size={52} />
                  <div style={{ flex: 1, minWidth: 0 }}>
                    {g.url ? (
                      <a
                        href={g.url}
                        target="_blank"
                        rel="noopener noreferrer"
                        style={{ fontSize: 15, fontWeight: 500, color: "#F5F0EC", textDecoration: "none", borderBottom: "1px solid #E11B23" }}
                      >
                        {g.title}
                      </a>
                    ) : (
                      <div style={{ fontSize: 15, fontWeight: 500, color: "#F5F0EC" }}>{g.title}</div>
                    )}
                    <div style={{ display: "flex", flexWrap: "wrap", gap: 6, marginTop: 6 }}>
                      {g.people.map((p) => (
                        <button
                          key={p.id}
                          type="button"
                          onClick={() => toggleFound(p.id)}
                          className="mono"
                          title={p.found ? "Mark as still wanted" : "Mark as found"}
                          style={{
                            fontSize: 11,
                            background: p.found ? "#0F1A14" : "#121212",
                            color: p.found ? "#6FA987" : "#E11B23",
                            padding: "3px 8px",
                            borderRadius: 20,
                            border: `1px solid ${p.found ? "#2E5240" : "#2A2A2A"}`,
                            textDecoration: p.found ? "line-through" : "none",
                            cursor: "pointer",
                            display: "inline-flex",
                            alignItems: "center",
                            gap: 4,
                          }}
                        >
                          {p.found && <CheckCircle2 size={11} color="#6FA987" />}
                          {p.name}
                        </button>
                      ))}
                    </div>
                  </div>
                </div>
              ))
            )}
          </div>
        )}

        {/* BY PERSON VIEW */}
        {view === "byPerson" && (
          <div>
            {loadingEntries ? (
              <EmptyState text="Loading the crate…" />
            ) : personGroups.length === 0 ? (
              <EmptyState text="No one's added a want yet." />
            ) : (
              personGroups.map((p) => (
                <div key={p.name} style={{ marginBottom: 22 }}>
                  <div
                    style={{
                      display: "flex",
                      alignItems: "center",
                      gap: 8,
                      marginBottom: 8,
                    }}
                  >
                    <User size={14} color="#E11B23" />
                    <span style={{ fontSize: 14.5, fontWeight: 600, color: "#F5F0EC" }}>{p.name}</span>
                    <span className="mono" style={{ fontSize: 11, color: "#9A9A9A" }}>
                      {p.items.length} item{p.items.length !== 1 ? "s" : ""}
                    </span>
                  </div>
                  {p.items.map((item) => (
                    <div
                      key={item.id}
                      className="entry-row"
                      style={{
                        display: "flex",
                        alignItems: "center",
                        gap: 10,
                        padding: "6px 4px 6px 22px",
                      }}
                    >
                      <RecordThumb src={item.thumb} alt={item.title} size={34} />
                      {item.url ? (
                        <a
                          href={item.url}
                          target="_blank"
                          rel="noopener noreferrer"
                          style={{
                            fontSize: 13.5,
                            color: item.found ? "#6B6B6B" : "#D8D3CC",
                            flex: 1,
                            textDecoration: item.found ? "line-through" : "none",
                            borderBottom: item.found ? "none" : "1px solid #E11B23",
                          }}
                        >
                          {item.title}
                        </a>
                      ) : (
                        <span
                          style={{
                            fontSize: 13.5,
                            color: item.found ? "#6B6B6B" : "#D8D3CC",
                            flex: 1,
                            textDecoration: item.found ? "line-through" : "none",
                          }}
                        >
                          {item.title}
                        </span>
                      )}
                      <button
                        onClick={() => toggleFound(item.id)}
                        title={item.found ? "Mark as still wanted" : "Mark as found"}
                        style={{
                          background: "none",
                          border: `1px solid ${item.found ? "#2E5240" : "#2A2A2A"}`,
                          color: item.found ? "#6FA987" : "#9A9A9A",
                          cursor: "pointer",
                          padding: "4px 8px",
                          borderRadius: 6,
                          fontSize: 11,
                          display: "flex",
                          alignItems: "center",
                          gap: 4,
                          flexShrink: 0,
                        }}
                      >
                        <CheckCircle2 size={12} />
                        {item.found ? "Found" : "Mark found"}
                      </button>
                      <button
                        onClick={() => removeEntry(item.id)}
                        title="Remove"
                        style={{
                          background: "none",
                          border: "none",
                          color: "#9A9A9A",
                          cursor: "pointer",
                          padding: 4,
                          flexShrink: 0,
                        }}
                      >
                        <X size={14} />
                      </button>
                    </div>
                  ))}
                </div>
              ))
            )}
          </div>
        )}
      </div>

      {toast && (
        <div
          className="toast"
          style={{
            position: "fixed",
            bottom: 24,
            left: "50%",
            transform: "translateX(-50%)",
            background: "#E11B23",
            color: "#F5F0EC",
            padding: "10px 18px",
            borderRadius: 8,
            fontSize: 13.5,
            fontWeight: 500,
            boxShadow: "0 6px 20px rgba(0,0,0,0.4)",
          }}
        >
          {toast}
        </div>
      )}
    </div>
  );
}

function EmptyState({ text }) {
  return (
    <div
      style={{
        textAlign: "center",
        padding: "48px 20px",
        color: "#9A9A9A",
        fontSize: 14,
        border: "1px dashed #2A2A2A",
        borderRadius: 12,
      }}
    >
      <Disc3 size={28} color="#2A2A2A" style={{ marginBottom: 10 }} />
      <div>{text}</div>
    </div>
  );
}
